namespace RecipeShare.Services;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = "";
    public string Category { get; set; } = "";
    public string CategorySlug { get; set; } = "";
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Bruschetta", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Baguette", "Tomatoes", "Basil", "Garlic", "Olive oil"],
            Steps = ["Toast bread slices", "Dice tomatoes and mix with basil and garlic", "Top bread with tomato mixture", "Drizzle with olive oil"],
            AverageRating = 4.2, RatingCount = 15
        },
        new()
        {
            Id = 2, Title = "Stuffed Mushrooms", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Button mushrooms", "Cream cheese", "Garlic", "Breadcrumbs", "Parsley"],
            Steps = ["Remove mushroom stems", "Mix filling ingredients", "Stuff mushroom caps", "Bake at 375°F for 20 minutes"],
            AverageRating = 4.5, RatingCount = 8
        },
        new()
        {
            Id = 3, Title = "Spaghetti Carbonara", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Parmesan", "Black pepper"],
            Steps = ["Cook pasta al dente", "Fry pancetta until crispy", "Whisk eggs with cheese", "Toss hot pasta with egg mixture and pancetta"],
            AverageRating = 4.8, RatingCount = 32
        },
        new()
        {
            Id = 4, Title = "Chicken Stir-Fry", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Chicken breast", "Bell peppers", "Soy sauce", "Ginger", "Rice"],
            Steps = ["Slice chicken and vegetables", "Stir-fry chicken until golden", "Add vegetables and sauce", "Serve over steamed rice"],
            AverageRating = 4.0, RatingCount = 20
        },
        new()
        {
            Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour"],
            Steps = ["Melt chocolate and butter", "Whisk eggs with sugar", "Fold in flour and chocolate mixture", "Bake at 425°F for 12 minutes"],
            AverageRating = 4.9, RatingCount = 45
        },
        new()
        {
            Id = 6, Title = "Tiramisu", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = ["Ladyfingers", "Mascarpone", "Espresso", "Cocoa powder", "Eggs"],
            Steps = ["Dip ladyfingers in espresso", "Make mascarpone cream with eggs", "Layer biscuits and cream", "Dust with cocoa and refrigerate overnight"],
            AverageRating = 4.7, RatingCount = 28
        }
    ];

    public List<Recipe> GetByCategory(string categorySlug)
        => _recipes.Where(r => r.CategorySlug == categorySlug).ToList();

    public Recipe? GetById(int id)
        => _recipes.FirstOrDefault(r => r.Id == id);

    public List<Recipe> GetAll() => _recipes;

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = totalStars / recipe.RatingCount;
    }
}

@page "/recipes"
@page "/recipes/{CategorySlug}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>Browse Recipes - RecipeShare</PageTitle>

<h1>@(CategorySlug is not null ? GetCategoryName() : "All Recipes")</h1>

<div class="row">
    @foreach (var recipe in GetRecipes())
    {
        <div class="col-md-6 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@recipe.Title</h5>
                    <p class="card-text text-muted">@recipe.Category</p>
                    <p class="card-text">
                        <span class="text-warning">@(new string('★', (int)Math.Round(recipe.AverageRating)))@(new string('☆', 5 - (int)Math.Round(recipe.AverageRating)))</span>
                        <small class="text-muted">(@recipe.RatingCount ratings)</small>
                    </p>
                    <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                </div>
            </div>
        </div>
    }
</div>

@if (!GetRecipes().Any())
{
    <p class="text-muted">No recipes found in this category.</p>
}

@code {
    [Parameter]
    public string? CategorySlug { get; set; }

    private List<Recipe> GetRecipes() =>
        CategorySlug is not null
            ? RecipeService.GetByCategory(CategorySlug)
            : RecipeService.GetAll();

    private string GetCategoryName() => CategorySlug switch
    {
        "appetizers" => "🥗 Appetizers",
        "main-courses" => "🍝 Main Courses",
        "desserts" => "🍰 Desserts",
        _ => "Recipes"
    };
}

@page "/recipe/{Id:int}"
@using RecipeShare.Services
@inject RecipeService RecipeService

@if (Recipe is not null)
{
    <PageTitle>@Recipe.Title - RecipeShare</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="recipes">Recipes</a></li>
            <li class="breadcrumb-item"><a href="recipes/@Recipe.CategorySlug">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>
    <p class="text-muted">Category: @Recipe.Category</p>

    <StarRating RecipeId="Recipe.Id" CurrentRating="Recipe.AverageRating" RatingCount="Recipe.RatingCount" />

    <h2 class="mt-4">Ingredients</h2>
    <ul>
        @foreach (var ingredient in Recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h2>Steps</h2>
    <ol>
        @foreach (var step in Recipe.Steps)
        {
            <li class="mb-2">@step</li>
        }
    </ol>
}
else
{
    <PageTitle>Recipe Not Found - RecipeShare</PageTitle>
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
    <a href="recipes" class="btn btn-primary">Browse All Recipes</a>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? Recipe { get; set; }

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="my-3">
    <span class="fs-4">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span role="button" @onclick="() => Rate(star)"
                  class="@(star <= _hovered ? "text-warning" : (star <= (int)Math.Round(CurrentRating) ? "text-warning" : "text-muted"))"
                  @onmouseover="() => _hovered = star"
                  @onmouseout="() => _hovered = 0"
                  style="cursor: pointer;">
                @(star <= (_hovered > 0 ? _hovered : (int)Math.Round(CurrentRating)) ? "★" : "☆")
            </span>
        }
    </span>
    <span class="ms-2 text-muted">
        @if (_submitted)
        {
            <span class="text-success">Thanks for rating!</span>
        }
        else
        {
            <span>@CurrentRating.ToString("F1") (@RatingCount ratings) — Click to rate</span>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int _hovered;
    private bool _submitted;

    private void Rate(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
        _submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "@_title" has been added.
        <a href="recipe/@_newRecipeId">View it here</a>.
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="_model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => _model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="_model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="Appetizers">Appetizers</option>
                <option value="Main Courses">Main Courses</option>
                <option value="Desserts">Desserts</option>
            </InputSelect>
            <ValidationMessage For="() => _model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="_model.Ingredients" class="form-control" rows="5"
                           placeholder="1 cup flour&#10;2 eggs&#10;1/2 cup sugar" />
            <ValidationMessage For="() => _model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="_model.Steps" class="form-control" rows="5"
                           placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
            <ValidationMessage For="() => _model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel _model = new();
    private bool _submitted;
    private string _title = "";
    private int _newRecipeId;

    private void HandleSubmit()
    {
        var categorySlug = _model.Category switch
        {
            "Appetizers" => "appetizers",
            "Main Courses" => "main-courses",
            "Desserts" => "desserts",
            _ => "other"
        };

        var recipe = new Recipe
        {
            Title = _model.Title,
            Category = _model.Category,
            CategorySlug = categorySlug,
            Ingredients = _model.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = _model.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        };

        RecipeService.AddRecipe(recipe);
        _title = recipe.Title;
        _newRecipeId = recipe.Id;
        _submitted = true;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required")]
        [System.ComponentModel.DataAnnotations.StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be 3-100 characters")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category")]
        public string Category { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one ingredient")]
        public string Ingredients { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one step")]
        public string Steps { get; set; } = "";
    }
}

