{"path": "/tmp/sv-db6caa319faa4b95a656736c0e4748aa/RecipeShare/Components/Pages/Recipes.razor", "file_text": "@page "/recipes"
@page "/recipes/{CategorySlug}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>Browse Recipes - RecipeShare</PageTitle>

<h1>@(CategorySlug is not null ? GetCategoryName() : "All Recipes")</h1>

<div class="row">
    @foreach (var recipe in GetRecipes())
    {
        <div class="col-md-6 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@recipe.Title</h5>
                    <p class="card-text text-muted">@recipe.Category</p>
                    <p class="card-text">
                        <span class="text-warning">@(new string('★', (int)Math.Round(recipe.AverageRating)))@(new string('☆', 5 - (int)Math.Round(recipe.AverageRating)))</span>
                        <small class="text-muted">(@recipe.RatingCount ratings)</small>
                    </p>
                    <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                </div>
            </div>
        </div>
    }
</div>

@if (!GetRecipes().Any())
{
    <p class="text-muted">No recipes found in this category.</p>
}

@code {
    [Parameter]
    public string? CategorySlug { get; set; }

    private List<Recipe> GetRecipes() =>
        CategorySlug is not null
            ? RecipeService.GetByCategory(CategorySlug)
            : RecipeService.GetAll();

    private string GetCategoryName() => CategorySlug switch
    {
        "appetizers" => "🥗 Appetizers",
        "main-courses" => "🍝 Main Courses",
        "desserts" => "🍰 Desserts",
        _ => "Recipes"
    };
}
"}

