+                  @onmouseout="() => _hovered = 0"
+                  style="cursor: pointer;">
+                @(star <= (_hovered > 0 ? _hovered : (int)Math.Round(CurrentRating)) ? "★" : "☆")
+            </span>
+        }
+    </span>
+    <span class="ms-2 text-muted">
+        @if (_submitted)
+        {
+            <span class="text-success">Thanks for rating!</span>
+        }
+        else
+        {
+            <span>@CurrentRating.ToString("F1") (@RatingCount ratings) — Click to rate</span>
+        }
+    </span>
+</div>
+
+@code {
+    [Parameter] public int RecipeId { get; set; }
+    [Parameter] public double CurrentRating { get; set; }
+    [Parameter] public int RatingCount { get; set; }
+
+    private int _hovered;
+    private bool _submitted;
+
+    private void Rate(int stars)
+    {
+        RecipeService.AddRating(RecipeId, stars);
+        var recipe = RecipeService.GetById(RecipeId);
+        if (recipe is not null)
+        {
+            CurrentRating = recipe.AverageRating;
+            RatingCount = recipe.RatingCount;
+        }
+        _submitted = true;
+    }
+}
+

toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "@_title" has been added.
        <a href="recipe/@_newRecipeId">View it here</a>.
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="_model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => _model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="_model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="Appetizers">Appetizers</option>
                <option value="Main Courses">Main Courses</option>
                <option value="Desserts">Desserts</option>
            </InputSelect>
            <ValidationMessage For="() => _model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="_model.Ingredients" class="form-control" rows="5"
                           placeholder="1 cup flour&#10;2 eggs&#10;1/2 cup sugar" />
            <ValidationMessage For="() => _model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="_model.Steps" class="form-control" rows="5"
                           placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
            <ValidationMessage For="() => _model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel _model = new();
    private bool _submitted;
    private string _title = "";
    private int _newRecipeId;

    private void HandleSubmit()
    {
        var categorySlug = _model.Category switch
        {
            "Appetizers" => "appetizers",
            "Main Courses" => "main-courses",
            "Desserts" => "desserts",
            _ => "other"
        };

        var recipe = new Recipe
        {
            Title = _model.Title,
            Category = _model.Category,
            CategorySlug = categorySlug,
            Ingredients = _model.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = _model.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        };

        RecipeService.AddRecipe(recipe);
        _title = recipe.Title;
        _newRecipeId = recipe.Id;
        _submitted = true;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required")]
        [System.ComponentModel.DataAnnotations.StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be 3-100 characters")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category")]
        public string Category { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one ingredient")]
        public string Ingredients { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one step")]
        public string Steps { get; set; } = "";
    }
}

