namespace RecipeShare.Services;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = "";
    public string Category { get; set; } = "";
    public string CategorySlug { get; set; } = "";
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Bruschetta", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Baguette", "Tomatoes", "Basil", "Garlic", "Olive oil"],
            Steps = ["Toast bread slices", "Dice tomatoes and mix with basil and garlic", "Top bread with tomato mixture", "Drizzle with olive oil"],
            AverageRating = 4.2, RatingCount = 15
        },
        new()
        {
            Id = 2, Title = "Stuffed Mushrooms", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Button mushrooms", "Cream cheese", "Garlic", "Breadcrumbs", "Parsley"],
            Steps = ["Remove mushroom stems", "Mix filling ingredients", "Stuff mushroom caps", "Bake at 375°F for 20 minutes"],
            AverageRating = 4.5, RatingCount = 8
        },
        new()
        {
            Id = 3, Title = "Spaghetti Carbonara", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Parmesan", "Black pepper"],
            Steps = ["Cook pasta al dente", "Fry pancetta until crispy", "Whisk eggs with cheese", "Toss hot pasta with egg mixture and pancetta"],
            AverageRating = 4.8, RatingCount = 32
        },
        new()
        {
            Id = 4, Title = "Chicken Stir-Fry", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Chicken breast", "Bell peppers", "Soy sauce", "Ginger", "Rice"],
            Steps = ["Slice chicken and vegetables", "Stir-fry chicken until golden", "Add vegetables and sauce", "Serve over steamed rice"],
            AverageRating = 4.0, RatingCount = 20
        },
        new()
        {
            Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour"],
            Steps = ["Melt chocolate and butter", "Whisk eggs with sugar", "Fold in flour and chocolate mixture", "Bake at 425°F for 12 minutes"],
            AverageRating = 4.9, RatingCount = 45
        },
        new()
        {
            Id = 6, Title = "Tiramisu", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = ["Ladyfingers", "Mascarpone", "Espresso", "Cocoa powder", "Eggs"],
            Steps = ["Dip ladyfingers in espresso", "Make mascarpone cream with eggs", "Layer biscuits and cream", "Dust with cocoa and refrigerate overnight"],
            AverageRating = 4.7, RatingCount = 28
        }
    ];

    public List<Recipe> GetByCategory(string categorySlug)
        => _recipes.Where(r => r.CategorySlug == categorySlug).ToList();

    public Recipe? GetById(int id)
        => _recipes.FirstOrDefault(r => r.Id == id);

    public List<Recipe> GetAll() => _recipes;

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = totalStars / recipe.RatingCount;
    }
}

